/*
 * COMP 421 Lab 1 - MonTTY Terminal Device Driver
 *
 * Implements a Mesa-style monitor with:
 *   - Echo priority over WriteTerminal output
 *   - Line-oriented ReadTerminal (blocks until '\n' or buflen chars)
 *   - \n -> \r\n expansion for output
 *   - Input character processing (backspace, \r/\n handling)
 *   - Full TerminalDriverStatistics
 *
 * Entry procedures (all call Declare_Monitor_Entry_Procedure as first stmt):
 *   ReceiveInterrupt, TransmitInterrupt
 *   WriteTerminal, ReadTerminal, InitTerminal,
 *   TerminalDriverStatistics, InitTerminalDriver
 */

#include <string.h>
#include <threads.h>
#include <hardware.h>
#include <terminals.h>

#define ERROR  (-1)

/*
 * Echo buffer: worst case is TERMINAL_MAX_LINE chars echoed forward
 * plus TERMINAL_MAX_LINE backspaces each producing 3 echo chars = 4x total.
 */
#define ECHO_BUF_SIZE   (TERMINAL_MAX_LINE * 4)

/*
 * Line input buffer: hold several queued lines (user may type ahead).
 */
#define LINE_BUF_SIZE   (TERMINAL_MAX_LINE * 4)


/* Per-terminal state */
static struct term_state {
    int initialized;

    /* Echo output ring buffer (highest priority) */
    char     echo_buf[ECHO_BUF_SIZE];
    int      echo_head;     /* dequeue from here */
    int      echo_tail;     /* enqueue here */
    int      echo_count;    /* chars queued */

    /* Current WriteTerminal state (one active writer at a time) */
    int      write_active;       /* 1 = a WriteTerminal is in progress */
    char    *write_buf;          /* user's output buffer */
    int      write_len;          /* total chars to write */
    int      write_pos;          /* next char index in write_buf */
    int      write_pending_nl;   /* 1 = must output '\n' of a \r\n expansion */

    /* Hardware transmit state */
    int      tx_busy;  /* 1 = hardware is currently transmitting */

    /* Input line buffer */
    char     line_buf[LINE_BUF_SIZE];
    int      line_len;   /* chars stored in line_buf[0..line_len-1] */
    int      line_edit;  /* start index of current (unfinished) editing line */

    /* Condition variables */
    cond_id_t read_cond;   /* ReadTerminal waits here for data */
    cond_id_t write_cond;  /* WriteTerminal serialization */
    cond_id_t tx_cond;     /* active writer waits here for transmit progress */

    /* Statistics */
    struct termstat stats;
} terms[NUM_TERMINALS];

/* Set to 1 after InitTerminalDriver is called */
static int driver_initialized = 0;


/* ==========================================================================
 * Static helper functions (not entry procedures)
 * ========================================================================== */

/*
 * Enqueue one character into the echo ring buffer for terminal term.
 * Drops the character silently if the buffer is full (shouldn't happen
 * in practice because the hardware rate-limits input).
 */
static void
enqueue_echo(int term, char c)
{
    struct term_state *t = &terms[term];

    if (t->echo_count < ECHO_BUF_SIZE) {
        t->echo_buf[t->echo_tail] = c;
        t->echo_tail = (t->echo_tail + 1) % ECHO_BUF_SIZE;
        t->echo_count++;
    }
}

/*
 * try_start_transmit - send the next pending output character to the hardware.
 *
 * Priority order:
 *   1. Echo chars (from keyboard input)
 *   2. Pending '\n' of a \r\n expansion
 *   3. Next char from the active WriteTerminal
 *
 * Called from ReceiveInterrupt and TransmitInterrupt.
 * Must be called with the monitor mutex held.
 * Does NOT block.
 */
static void
try_start_transmit(int term)
{
    struct term_state *t = &terms[term];
    char c;

    if (t->tx_busy)
        return;  /* hardware busy; nothing to do yet */

    /* Echo has highest priority */
    if (t->echo_count > 0) {
        c = t->echo_buf[t->echo_head];
        t->echo_head = (t->echo_head + 1) % ECHO_BUF_SIZE;
        t->echo_count--;
        WriteDataRegister(term, c);
        t->tx_busy = 1;
        t->stats.tty_out++;
        return;
    }

    /* Second byte of a \n -> \r\n expansion */
    if (t->write_pending_nl) {
        t->write_pending_nl = 0;
        WriteDataRegister(term, '\n');
        t->tx_busy = 1;
        t->stats.tty_out++;
        return;
    }

    /* Normal WriteTerminal output */
    if (t->write_pos < t->write_len) {
        c = t->write_buf[t->write_pos++];
        if (c == '\n') {
            /* Expand '\n' to '\r\n': send '\r' now, '\n' next time */
            WriteDataRegister(term, '\r');
            t->write_pending_nl = 1;
        } else {
            WriteDataRegister(term, c);
        }
        t->tx_busy = 1;
        t->stats.tty_out++;
        return;
    }

    /* Nothing to send */
}


/* ==========================================================================
 * Monitor entry procedures
 * ========================================================================== */

/*
 * InitTerminalDriver - must be called exactly once before any other API call.
 */
int
InitTerminalDriver(void)
{
    Declare_Monitor_Entry_Procedure();

    if (driver_initialized)
        return ERROR;

    memset(terms, 0, sizeof(terms));
    driver_initialized = 1;
    return 0;
}

/*
 * InitTerminal - initialize terminal number term.
 * Before this call, statistics for this terminal are -1 (handled in
 * TerminalDriverStatistics).  After this call, statistics are all 0.
 */
int
InitTerminal(int term)
{
    struct term_state *t;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (terms[term].initialized)
        return ERROR;

    if (InitHardware(term) != 0)
        return ERROR;

    t = &terms[term];
    memset(t, 0, sizeof(*t));   /* clears stats to 0 and all flags */
    t->initialized = 1;
    t->read_cond   = CondCreate();
    t->write_cond  = CondCreate();
    t->tx_cond     = CondCreate();
    return 0;
}

/*
 * TerminalDriverStatistics - return a consistent snapshot of I/O statistics.
 * Uninitialized terminals report all fields as -1.
 */
int
TerminalDriverStatistics(struct termstat *stats)
{
    int i;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)
        return ERROR;
    if (stats == NULL)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++) {
        if (!terms[i].initialized) {
            stats[i].tty_in  = -1;
            stats[i].tty_out = -1;
            stats[i].user_in = -1;
            stats[i].user_out = -1;
        } else {
            stats[i] = terms[i].stats;
        }
    }
    return 0;
}

/*
 * WriteTerminal - write buflen chars from buf to terminal term.
 *
 * Serialized: only one writer active per terminal at a time.
 * Blocks until all characters have been placed in the output register.
 * '\n' characters are expanded to '\r\n'.
 * Echo output always has priority over WriteTerminal output.
 */
int
WriteTerminal(int term, char *buf, int buflen)
{
    struct term_state *t;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terms[term].initialized)
        return ERROR;
    if (buf == NULL)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;

    t = &terms[term];
    t->stats.user_in += buflen;

    /* Serialize: wait until no other writer is active on this terminal */
    while (t->write_active)
        CondWait(t->write_cond);

    /* Set up this write operation */
    t->write_active    = 1;
    t->write_buf       = buf;
    t->write_len       = buflen;
    t->write_pos       = 0;
    t->write_pending_nl = 0;

    /* Kick off transmission if hardware is idle */
    try_start_transmit(term);

    /*
     * Wait until all chars have been placed in the output register.
     * TransmitInterrupt will call try_start_transmit and signal tx_cond
     * on each completion.
     */
    while (t->write_pos < t->write_len || t->write_pending_nl)
        CondWait(t->tx_cond);

    /* Release exclusive access; wake next waiting writer */
    t->write_active = 0;
    CondSignal(t->write_cond);

    return buflen;
}

/*
 * ReadTerminal - read the next line (up to buflen chars) from terminal term.
 *
 * Blocks until:
 *   - a complete line ('\n' terminated) is available, OR
 *   - buflen characters are available (whichever comes first).
 * Returns up to buflen chars, stopping at '\n' inclusive.
 * Remaining chars stay in the buffer for the next ReadTerminal call.
 */
int
ReadTerminal(int term, char *buf, int buflen)
{
    struct term_state *t;
    int i, has_nl, to_copy, remaining;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terms[term].initialized)
        return ERROR;
    if (buf == NULL && buflen > 0)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;

    t = &terms[term];

    /* Wait until a complete line or buflen chars are available */
    while (1) {
        has_nl = 0;
        for (i = 0; i < t->line_len; i++) {
            if (t->line_buf[i] == '\n') {
                has_nl = 1;
                break;
            }
        }
        if (has_nl || t->line_len >= buflen)
            break;
        CondWait(t->read_cond);
    }

    /* Copy up to buflen chars, stopping after the first '\n' */
    to_copy = 0;
    for (i = 0; i < t->line_len && to_copy < buflen; i++) {
        buf[to_copy++] = t->line_buf[i];
        if (t->line_buf[i] == '\n')
            break;
    }

    /* Remove consumed chars from the front of the buffer */
    remaining = t->line_len - to_copy;
    if (remaining > 0)
        memmove(t->line_buf, t->line_buf + to_copy, (size_t)remaining);
    t->line_len  = remaining;
    t->line_edit -= to_copy;
    if (t->line_edit < 0)
        t->line_edit = 0;

    t->stats.user_out += to_copy;

    /* Wake another waiting reader if data remains */
    if (t->line_len > 0)
        CondSignal(t->read_cond);

    return to_copy;
}

/*
 * ReceiveInterrupt - called by hardware for each key press on terminal term.
 *
 * Must NOT block (no CondWait).
 * Reads the character, processes it (echo + line buffer), and queues echo output.
 */
void
ReceiveInterrupt(int term)
{
    struct term_state *t;
    int line_avail;
    char c;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS)
        return;
    t = &terms[term];
    if (!t->initialized)
        return;

    c = ReadDataRegister(term);
    t->stats.tty_in++;

    /* Number of chars in the current unfinished editing line */
    line_avail = t->line_len - t->line_edit;

    if (c == '\r' || c == '\n') {
        /*
         * CR or LF: echo as \r\n, store '\n' in line buffer to mark
         * end of line, and wake any waiting readers.
         */
        enqueue_echo(term, '\r');
        enqueue_echo(term, '\n');
        if (t->line_len < LINE_BUF_SIZE) {
            t->line_buf[t->line_len++] = '\n';
            t->line_edit = t->line_len; /* editing of next line starts here */
        }
        CondSignal(t->read_cond);

    } else if (c == '\b' || c == '\177') {
        /*
         * Backspace (0x08) or Delete (0x7F): remove the last character
         * from the current editing line.  Echo \b SP \b to erase on screen.
         * If the line is empty, do nothing (no echo).
         */
        if (line_avail > 0) {
            t->line_len--;
            enqueue_echo(term, '\b');
            enqueue_echo(term, ' ');
            enqueue_echo(term, '\b');
        }

    } else {
        /*
         * Regular character: add to line buffer if there is room in
         * the current editing line (up to TERMINAL_MAX_LINE chars).
         * Echo the character.  Signal readers in case a buflen-based
         * read can now be satisfied.
         */
        if (line_avail < TERMINAL_MAX_LINE && t->line_len < LINE_BUF_SIZE) {
            t->line_buf[t->line_len++] = c;
            enqueue_echo(term, c);
            CondSignal(t->read_cond);
        }
        /* else: buffer full — silently drop the character */
    }

    /* Start echoing if the hardware is currently idle */
    try_start_transmit(term);
}

/*
 * TransmitInterrupt - called by hardware after each character is transmitted.
 *
 * Clears the busy flag, tries to start the next output character, and
 * wakes any writer waiting in WriteTerminal.
 */
void
TransmitInterrupt(int term)
{
    struct term_state *t;

    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS)
        return;
    t = &terms[term];
    if (!t->initialized)
        return;

    t->tx_busy = 0;
    try_start_transmit(term);
    CondSignal(t->tx_cond); /* let the active writer check if it is done */
}
